var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"안젤라 씨! 어디 있어요!","JPN":"アンジェラさん！　どこですか！","ENG":"Angela! Where are you?","TWN":"安潔拉小姐！你在哪！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"안젤라 씨!","JPN":"アンジェラさん！","ENG":"Angela!","TWN":"安潔拉小姐！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"크헉……!","JPN":"くはっ……！","ENG":"Hngh!?","TWN":"唔……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"여인의 소재를 말하라. 그리하면 목숨을 해치지 않으리니.","JPN":"女の居場所を話せ。そうしたら命は助けてやろう。","ENG":"Name the whereabouts of the woman. So your life may be spared.","TWN":"說出女人在哪裡，我就饒你不死。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"힉……! 히익……!","JPN":"ひ……！　ひいっ……！","ENG":"E-eeek!","TWN":"嗚……！嗚嗚……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"지, 지하실! 지하실에 가뒀다는 얘길 들었습니다!","JPN":"ち、地下室！　地下室に閉じ込めたって聞きました！","ENG":"B-basement! I heard she was locked in the basement!","TWN":"她…她在地下室！我聽說她被關在地下室裡！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"그것뿐이에요! 제발 살려 주십시오!","JPN":"それだけです！　どうか助けてください！","ENG":"That’s all I know! S-s-pare me!","TWN":"我就只知道這些！拜託別殺我！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……지하실인가. 알겠다.","JPN":"……地下室か。承知した。","ENG":"...The basement. Understood.","TWN":"……在地下室嗎？好。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"무기가 전혀 통하지 않아! 지원을 요청해!","JPN":"武器がまったく通じない！　支援を呼べ！","ENG":"Weapons aren’t working at all! Call for backup!","TWN":"武器對她根本沒有效！快請求支援！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"처, 천장이 무너진다!! 도망쳐!","JPN":"て、天井が崩れる！！　逃げろ！","ENG":"The c-ceiling is collapsing!! Run away!","TWN":"天…天花板要塌啦！！大家快逃！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저, 정신 나간 녀석인 줄은 알았지만……. 정부군이랑 혼자 전쟁이라도 벌이려는 건가?","JPN":"しょ、正気じゃない奴なのはわかってたけど……一人で政府軍と戦争でも起こそうとしてるの？","ENG":"I already knew she was crazy but... Is she really going to take on the entire government alone?","TWN":"我…我還以為她只是精神不正常……結果她是打算單獨和政府軍開戰嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아니, 이럴 때가 아니지. 레버넌트 씨가 저 자랑 마주쳤다간…….","JPN":"いや、こうしている場合じゃない。レヴナントさんがあれと出くわしたら……","ENG":"No, this isn’t the time for that. I can’t let Revenant run into that monster...","TWN":"不對，現在不是想這些的時候，萬一我錯過亡靈小姐……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사……? 여기서 뭐 하고 있어?","JPN":"軍曹……？　ここで何してるの？","ENG":"Sergeant...? What are you doing here?","TWN":"中士……？你在這裡做什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트 씨?!","JPN":"レヴナントさん！？","ENG":"Revenant?!","TWN":"亡靈小姐？！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"정말 레버넌트 씨 맞아요? 지하실에 갇혀 있던 거 아니었어요?","JPN":"本当にレヴナントさんなんですか？　地下室に閉じ込められてたんじゃなかったんですか？","ENG":"Is that really you, Revenant? Weren’t you being kept in the basement?","TWN":"真的是你？你不是被關在地下室嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그건……. 윽……!","JPN":"それは……うっ……！","ENG":"That’s... Ugh...!","TWN":"因為……呃……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"상태는 또 왜 이래요? 설마 지하실에서…….","JPN":"体はまたどうしたんですか？　まさか地下室で……","ENG":"You’re in really rough shape. It can’t be... In the basement they...","TWN":"你怎麼又這副慘樣？該不會他們在地下室對你……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그냥, 잠 좀 못 잔 정도지.","JPN":"ただ、ちょっと眠れなかっただけだよ。","ENG":"I just... haven’t been able to sleep much.","TWN":"沒有啦，只是不讓我睡覺而已。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사야말로…… 보안국에 웬일로 온 거야? 견학 코스로는 영 아닌 곳인데?","JPN":"軍曹こそ……保安局になんの用？　見学コースには向いてない場所だけど？","ENG":"Sergeant...why are you at the National Security? It’s not exactly a big tourist destination.","TWN":"倒是你……來安全局做什麼？這邊應該不是校外教學的地點吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그게, 안젤라 씨가 멋대로 먼저 가는 바람에…….","JPN":"それが、アンジェラさんが勝手に先走って……","ENG":"That’s, well, Angela just went first...","TWN":"就…安潔拉小姐自顧自地出發後……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"안젤라? 안젤라도 여기 와 있어?","JPN":"アンジェラ？　アンジェラもここに来てるの？","ENG":"Angela? Angela is here too?","TWN":"安潔拉？安潔拉也在這裡？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네. 그 쇳덩어리가 지금 청사를 헤집고 다니는 중이에요. 혹시나 잘못 마주치면…….","JPN":"はい。あの鉄の塊が今庁舎内をかき回してますよ。もし下手に出くわしたら……","ENG":"Yeah, and that mass of iron is running around the building too. If she runs into her...","TWN":"對，那個大鐵塊現在也在這裡，萬一她們遇到的話……。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아니. 녀석은 날 노리는 눈치였어. 가자.","JPN":"いや。奴は私を狙ってるみたいだった。行こう。","ENG":"No, it’ll be okay. That bastard seemed like she was after me.","TWN":"嗯嗯，那傢伙的目標是我，快走吧！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"잠깐만요! 레버넌트 씨를 걱정해서 왔는데 버리겠다고요?","JPN":"待ってください！　レヴナントさんが心配で来たのに、見捨てるんですか？","ENG":"Hold on! She came here because she was worried about you, and you’re just going to leave her?","TWN":"先等一下！安潔拉小姐是因為擔心你才來的，你現在要扔下她嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사. 내가 안젤라와 어떻게 만났는지 얘기했던 거, 기억해?","JPN":"軍曹。私がアンジェラとどうやって出会ったか話したの、覚えてる？","ENG":"Sergeant. I told you how Angela and I met, remember?","TWN":"中士，你還記得我跟你說過，我和安潔拉是怎麼認識的吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……그, 죽으려고 하는 걸 말렸다는 얘기 말이죠?","JPN":"……その、死のうとしたのを止めてくれたって話ですか？","ENG":"...You mean, when she stopped you from killing yourself?","TWN":"……你說你想自殺，是她攔住你的對吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"사실 거짓말이야. 실제로 거의 성공했어.","JPN":"実はウソなんだ。本当はほぼ成功してた。","ENG":"That was a lie. To be honest, I almost succeeded.","TWN":"我是騙你的，其實我當初差點成功。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그런데 정신을 차려 보니……. 안젤라가 무척 화난 표정으로 보고 있었지.","JPN":"でも目が覚めたら……アンジェラがものすごく怒った顔で見ていたの。","ENG":"But when I came to myself... Angela was looking at me with a furious look.","TWN":"當我清醒過來後……看到安潔拉用非常憤怒的表情盯著我。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마와 내 손목에 냈던 상처는, 깨끗하게 사라진 뒤였어.","JPN":"お母さんと私の手首についた傷は、綺麗になくなってたよ。","ENG":"The cuts on my mom’s and my wrists had completely disappeared.","TWN":"而那是在我媽和我手腕上的傷消失之後的事。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마에게는……. 정말 몹쓸 짓을 한 셈이지.","JPN":"お母さんには……本当ひどいことをしたね。","ENG":"To do that to my own mom... That was an incredibly horrible thing to do.","TWN":"我真的……對媽媽做了很可怕的事。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"알겠어? 자기 입으로 말한 적은 없지만, 안젤라는 분명 카운터야.","JPN":"わかった？　自分から言ったことはないけど、アンジェラは確かなカウンターなの。","ENG":"You get it now? She's never said this before, but Angela’s definitely a Counter.","TWN":"你知道嗎？雖然安潔拉從沒提過，但她一定就是制裁者。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"전쟁통에도 함께 해 온 사이니까, 무사할 거라고 믿을 수 있어. 지금은 중사가 더 급해.","JPN":"戦争の中でも一緒にやってきた仲だから、無事だと信じられる。今は軍曹が先。","ENG":"We’ve already been through war together so I know she’ll be okay. Right now, your safety is the pressing issue.","TWN":"我們曾經一起在戰場上並肩作戰過，我相信她一定會沒事的，現在是你比較要緊。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"왜 그래, 중사?","JPN":"どうしたの、軍曹？","ENG":"What's wrong, Sergeant?","TWN":"你怎麼了？中士？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그, 그게, 레버넌트 씨. 뒤에…….","JPN":"そ、それが、レヴナントさん。後ろに……","ENG":"Revenant, th-that’s... Behind you...","TWN":"那個…你後面……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님, 저희보다 먼저 온 손님이 계셨군요.","JPN":"副戦隊長、先客がいましたね。","ENG":"Deputy Commander, it appears another guest arrived before us.","TWN":"副戰隊長，看來有人比我們早到呢。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……그러게?","JPN":"……そうね？","ENG":"...Is that so?","TWN":"……是嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"인기가 많아서 좋겠어, 레버넌트 씨.","JPN":"人気者でよかったわね、レヴナントさん。","ENG":"It must be so nice to be this popular, Revenant.","TWN":"人氣這麼旺，好羨慕你喔，亡靈。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};